function findMaxConsecutiveOnes(nums) {
    let maxCount = 0, countZeros = 0, left = 0;
    for (let right = 0; right < nums.length; ++right) {
        if (nums[right] === 0) countZeros++;
        while (countZeros > 1) {
            if (nums[left++] === 0) countZeros--;
        }
        maxCount = Math.max(maxCount, right - left + 1);
    }
    return maxCount;
}
